sections.code:
p { color: black; }
.title { color: blue; }
#hero { color: #0080ff; }

.site-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  min-height: 64px;
}

.skills {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.skill-tag {
  padding: 6px 12px;
  border: 2px solid #1d1d1b;
  border-radius: 999px;
}

.project-card__body {
  display: flex;
  gap: 16px;
}

.project-card__text {
  flex: 1;
}

.project-card__link {
  flex: 0 0 auto;
}

.projects {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 20px;
}

.projects {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--space-4, 16px);
}

.page {
  display: grid;
  grid-template-areas:
    "header"
    "main"
    "footer";
  gap: 24px;
}

.site-header { grid-area: header; }
.site-main { grid-area: main; }
.site-footer { grid-area: footer; }

.skill-icon-grid {
  display: grid;
  grid-template-columns: repeat(4, 64px);
  gap: 12px;
  place-items: center;
}

.projects {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
}

@media (min-width: 768px) {
  .projects {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (min-width: 1024px) {
  .projects {
    grid-template-columns: repeat(3, 1fr);
  }
}

.project-card {
  position: relative;
}

.project-card__badge {
  position: absolute;
  top: 12px;
  right: 12px;
  padding: 4px 8px;
  border-radius: 8px;
  background: #0080ff;
  color: #fff;
}

.nav-overlay {
  position: fixed;
  inset: 0;
  z-index: 50;
  background: rgb(29 29 27 / 60%);
}

.project-card__thumb {
  aspect-ratio: 16 / 9;
  overflow: hidden;
  border-radius: 16px;
}

.project-card__thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.btn {
  background: #fff;
  transition: background-color 0.2s ease, color 0.2s ease;
}

.btn:hover {
  background: #0080ff;
  color: #fff;
}

.project-card {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.project-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 24px rgb(29 29 27 / 12%);
}

.project-card {
  cursor: pointer;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.project-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 32px rgb(0 128 255 / 15%);
}

.link:hover {
  color: #0080ff;
  text-decoration: underline;
  text-underline-offset: 4px;
}

task.starter:
.btn {
  padding: 8px 16px;
  border: 2px solid #1d1d1b;
  cursor: pointer;
  transition: background 0.2s;
}

.btn:hover {

  color: #fff;
}

sections.code:
*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: Arial, sans-serif;
  color: var(--color-text, #1d1d1b);
}

ul, ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

.flex { display: flex; }
.flex-col { flex-direction: column; }
.gap-4 { gap: var(--space-4, 16px); }
.text-center { text-align: center; }
.u-sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
}

.section-title::after {
  content: "";
  display: block;
  width: 48px;
  height: 4px;
  margin-top: 12px;
  background: var(--color-primary, #0080ff);
  border-radius: 2px;
}

.site-nav {
  display: flex;
  gap: 24px;
  list-style: none;
  margin: 0;
  padding: 0;
}

.site-nav a {
  text-decoration: none;
  color: inherit;
}

a,
button,
.project-card--clickable {
  cursor: pointer;
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

a:focus-visible,
button:focus-visible {
  outline: 3px solid rgb(0 128 255 / 45%);
  outline-offset: 3px;
}

a:focus:not(:focus-visible) {
  outline: none;
}

.project-card {
  display: flex;
  flex-direction: column;
  gap: var(--space-4, 16px);
  padding: var(--space-4, 16px);
  border: 2px solid #1d1d1b;
  border-radius: var(--radius-lg, 24px);
  background: #fff;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.project-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 32px rgb(29 29 27 / 10%);
}

.project-card__thumb {
  aspect-ratio: 16 / 9;
  overflow: hidden;
  border-radius: 16px;
}

:root {
  --color-primary: #0080ff;
  --color-text: #1d1d1b;
  --space-4: 16px;
  --space-6: 24px;
  --radius-lg: 24px;
  --container: 1120px;
}

body {
  margin: 0;
  font-family: Arial, sans-serif;
  color: var(--color-text);
  line-height: 1.5;
}

task.starter:
body {
  margin: 0;
  font-family: Arial, sans-serif;
  color: var(--color-text, #1d1d1b);

}
